package com.school.config;
import com.school.security.DatabaseUserDetailsService; import org.springframework.context.annotation.*; import org.springframework.security.authentication.dao.DaoAuthenticationProvider; import org.springframework.security.config.annotation.web.builders.HttpSecurity; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.security.web.SecurityFilterChain;
@Configuration public class SecurityConfig { @Bean PasswordEncoder passwordEncoder(){return new BCryptPasswordEncoder();} @Bean DaoAuthenticationProvider authProvider(DatabaseUserDetailsService service,PasswordEncoder encoder){var p=new DaoAuthenticationProvider();p.setUserDetailsService(service);p.setPasswordEncoder(encoder);return p;} @Bean SecurityFilterChain filterChain(HttpSecurity http,DaoAuthenticationProvider provider)throws Exception{return http.authenticationProvider(provider).authorizeHttpRequests(a->a.requestMatchers("/css/**","/js/**","/login","/error").permitAll().requestMatchers("/admin/**").hasRole("ADMIN").requestMatchers("/lecturer/**").hasRole("LECTURER").requestMatchers("/student/**").hasRole("STUDENT").anyRequest().authenticated()).formLogin(f->f.loginPage("/login").successHandler((req,res,auth)->{boolean admin=auth.getAuthorities().stream().anyMatch(x->x.getAuthority().equals("ROLE_ADMIN"));boolean lecturer=auth.getAuthorities().stream().anyMatch(x->x.getAuthority().equals("ROLE_LECTURER"));res.sendRedirect(admin?"/admin/dashboard":lecturer?"/lecturer/dashboard":"/student/dashboard");}).permitAll()).logout(l->l.logoutSuccessUrl("/login?logout")).exceptionHandling(e->e.accessDeniedPage("/403")).build();} }
